INSERT INTO questions (id, topic_nr, topic, level, question, answer_a, answer_b, answer_c, answer_d, solution, source_hint) VALUES
  ('TF01-001', 1, 'Einführung und Grundlagen der IT-Sicherheit und rechtlicher Rahmenbedingungen', 'Basis', 'Welche Aussagen beschreiben Informationssicherheit im Sinne eines ganzheitlichen Sicherheitsansatzes?', 'Sie umfasst technische, organisatorische, personelle und infrastrukturelle Maßnahmen.', 'Sie betrachtet nur Systeme, auf denen elektronische Daten gespeichert werden.', 'Sie schützt Informationen unabhängig davon, ob diese digital, auf Papier oder mündlich verarbeitet werden.', 'Sie endet, sobald eine Firewall und ein Virenschutz eingeführt wurden.', ARRAY['A','C'], 'Online-Kurs Lektion 1 und 2'),
  ('TF01-002', 1, 'Einführung und Grundlagen der IT-Sicherheit und rechtlicher Rahmenbedingungen', 'Basis', 'Welche drei klassischen Grundwerte werden mit der CIA-Triade der Informationssicherheit verbunden?', 'Vertraulichkeit, Integrität und Verfügbarkeit', 'Authentisierung, Autorisierung und Accounting', 'Prävention, Detektion und Reaktion', 'Planung, Umsetzung und Verbesserung', ARRAY['A'], 'Grundlagen Informationssicherheit'),
  ('TF01-003', 1, 'Einführung und Grundlagen der IT-Sicherheit und rechtlicher Rahmenbedingungen', 'Basis', 'Welche Ursachen können nach dem Grundverständnis des IT-Grundschutzes zu Gefährdungen für Informationen und IT führen?', 'Fahrlässiges Verhalten von Beschäftigten', 'Technische Mängel oder Ausfälle', 'Naturereignisse oder höhere Gewalt', 'Ausschließlich vorsätzliche externe Angriffe', ARRAY['A','B','C'], 'Online-Kurs Lektion 1.1'),
  ('TF01-004', 1, 'Einführung und Grundlagen der IT-Sicherheit und rechtlicher Rahmenbedingungen', 'Basis', 'Wann gelten Sicherheitsmaßnahmen als angemessen?', 'Wenn sie zum Schutzbedarf und zur tatsächlichen Gefährdungslage passen.', 'Wenn sie unabhängig vom Bedarf immer das technisch maximal mögliche Niveau erreichen.', 'Wenn sie wirksam sind, ohne die Institution unverhältnismäßig zu überfordern.', 'Wenn sie ausschließlich nach den geringsten Anschaffungskosten ausgewählt werden.', ARRAY['A','C'], 'Online-Kurs Lektion 1.1'),
  ('TF01-005', 1, 'Einführung und Grundlagen der IT-Sicherheit und rechtlicher Rahmenbedingungen', 'Basis', 'Welche externen Anforderungen können Sicherheitsziele einer Institution beeinflussen?', 'Gesetzliche oder regulatorische Vorgaben', 'Eine interne Gestaltungsvorgabe ohne Sicherheitsbezug', 'Eine persönliche Risikoakzeptanz eines Administrators ohne Mandat', 'Ein Produktdatenblatt ohne verbindliche Sicherheitsanforderung', ARRAY['A'], 'Online-Kurs Lektion 2.2'),
  ('TF01-006', 1, 'Einführung und Grundlagen der IT-Sicherheit und rechtlicher Rahmenbedingungen', 'Basis', 'Welche Aufgaben liegen typischerweise bei der obersten Leitung im Sicherheitsprozess?', 'Sie setzt Ziele und Rahmenbedingungen für Informationssicherheit.', 'Sie übernimmt jede technische Einzelkonfiguration selbst.', 'Sie delegiert die Verantwortung vollständig an externe Dienstleister.', 'Sie beschafft ausschließlich die günstigsten Produkte.', ARRAY['A'], 'Online-Kurs Lektion 2.2'),
  ('TF01-007', 1, 'Einführung und Grundlagen der IT-Sicherheit und rechtlicher Rahmenbedingungen', 'Experte', 'Welche rechtlichen Rahmenbedingungen können für eine Institution relevant sein, wenn sie personenbezogene Daten verarbeitet?', 'DSGVO und BDSG', 'Nur interne Richtlinien, keine gesetzlichen Vorgaben', 'Nur die Allgemeinen Geschäftsbedingungen des Cloud-Anbieters', 'Ausschließlich die ISO 9001', ARRAY['A'], 'Online-Kurs Lektion 2.2 und DSGVO'),
  ('TF01-008', 1, 'Einführung und Grundlagen der IT-Sicherheit und rechtlicher Rahmenbedingungen', 'Experte', 'Welche Aussagen treffen auf die DSGVO zu?', 'Sie gilt für alle Unternehmen, die personenbezogene Daten von EU-Bürgern verarbeiten.', 'Sie erfordert eine Rechtsgrundlage für die Datenverarbeitung.', 'Sie verbietet jegliche Datenverarbeitung ohne Ausnahme.', 'Sie setzt keine Anforderungen an die technische und organisatorische Sicherheit.', ARRAY['A','B'], 'Online-Kurs Lektion 2.2 und DSGVO'),
  ('TF02-001', 2, 'Normen und Standards der Informationssicherheit', 'Basis', 'Welche Normen und Standards sind im Bereich der Informationssicherheit relevant?', 'ISO/IEC 27001', 'ISO/IEC 27002', 'IT-Grundschutz-Kompendium', 'DIN EN 60601', ARRAY['A','B','C'], 'Online-Kurs Lektion 3'),
  ('TF02-002', 2, 'Normen und Standards der Informationssicherheit', 'Basis', 'Was beschreibt die ISO/IEC 27001?', 'Anforderungen an ein Informationssicherheitsmanagementsystem (ISMS)', 'Eine Sammlung von IT-Grundschutz-Bausteinen', 'Eine Checkliste für Penetrationstests', 'Eine Norm für medizinische Geräte', ARRAY['A'], 'Online-Kurs Lektion 3'),
  ('TF02-003', 2, 'Normen und Standards der Informationssicherheit', 'Basis', 'Was ist der Zweck der ISO/IEC 27002?', 'Sie bietet Leitlinien und bewährte Verfahren für Informationssicherheitsmaßnahmen.', 'Sie definiert die Anforderungen für eine Zertifizierung.', 'Sie ist ausschließlich für Behörden gedacht.', 'Sie ersetzt den IT-Grundschutz vollständig.', ARRAY['A'], 'Online-Kurs Lektion 3'),
  ('TF02-004', 2, 'Normen und Standards der Informationssicherheit', 'Basis', 'Welche Aussagen zum IT-Grundschutz-Kompendium sind korrekt?', 'Es enthält Bausteine, die auf typische Bedrohungen und Maßnahmen eingehen.', 'Es ist ein offizieller BSI-Standard.', 'Es ersetzt die ISO 27001.', 'Es ist nur für kleine Unternehmen gedacht.', ARRAY['A','B'], 'Online-Kurs Lektion 3'),
  ('TF02-005', 2, 'Normen und Standards der Informationssicherheit', 'Experte', 'Welche Unterschiede gibt es zwischen ISO 27001 und IT-Grundschutz?', 'ISO 27001 ist eine internationale Norm für ISMS-Zertifizierung, IT-Grundschutz ist ein deutscher Standard mit konkreten Bausteinen.', 'Es gibt keine Unterschiede, beide sind identisch.', 'IT-Grundschutz ist nur für Behörden, ISO 27001 nur für Unternehmen.', 'ISO 27001 ist veraltet und wurde durch IT-Grundschutz ersetzt.', ARRAY['A'], 'Online-Kurs Lektion 3'),
  ('TF02-006', 2, 'Normen und Standards der Informationssicherheit', 'Experte', 'Welche Anforderungen stellt die ISO 27001 an ein ISMS?', 'Risikomanagement und regelmäßige Überprüfung', 'Dokumentation von Sicherheitsrichtlinien', 'Kontinuierliche Verbesserung', 'Ausschließlich technische Maßnahmen', ARRAY['A','B','C'], 'Online-Kurs Lektion 3'),
  ('TF02-007', 2, 'Normen und Standards der Informationssicherheit', 'Basis', 'Welche Aussagen zur BSI-Grundschutz-Methodik sind richtig?', 'Sie basiert auf einem modularen Aufbau mit Bausteinen.', 'Sie ist an die ISO 27001 anlehnbar.', 'Sie erfordert eine Risikoanalyse.', 'Sie ist ausschließlich für den öffentlichen Sektor.', ARRAY['A','B','C'], 'Online-Kurs Lektion 3'),
  ('TF02-008', 2, 'Normen und Standards der Informationssicherheit', 'Basis', 'Welche Rolle spielt der BSI in der Informationssicherheit?', 'Er entwickelt den IT-Grundschutz und das IT-Grundschutz-Kompendium.', 'Er ist ausschließlich für die militärische Sicherheit zuständig.', 'Er zertifiziert nur ISO 27001.', 'Er hat keine Aufgaben in der Informationssicherheit.', ARRAY['A'], 'Online-Kurs Lektion 3'),
  ('TF03-001', 3, 'Einführung IT-Grundschutz', 'Basis', 'Was ist der IT-Grundschutz?', 'Ein Standard des BSI zur Informationssicherheit', 'Eine Sammlung von Bausteinen zur Absicherung von IT-Systemen', 'Ein Gesetz zur Datensicherheit', 'Ein Softwaretool zur Virenerkennung', ARRAY['A','B'], 'Online-Kurs Lektion 4'),
  ('TF03-002', 3, 'Einführung IT-Grundschutz', 'Basis', 'Welche Ziele verfolgt der IT-Grundschutz?', 'Angemessene Sicherheit für Informationen und IT-Systeme', 'Vollständige Absicherung gegen alle Bedrohungen', 'Praktikable und wirtschaftlich vertretbare Maßnahmen', 'Ausschließlich technische Absicherung', ARRAY['A','C'], 'Online-Kurs Lektion 4'),
  ('TF03-003', 3, 'Einführung IT-Grundschutz', 'Basis', 'Welche Elemente umfasst der IT-Grundschutz?', 'IT-Grundschutz-Profile', 'IT-Grundschutz-Kompendium', 'IT-Grundschutz-Vorgehensweise', 'IT-Grundschutz-Check', ARRAY['A','B','C','D'], 'Online-Kurs Lektion 4'),
